import React, { useEffect, useState, useCallback, useMemo } from 'react';
import axios from 'axios';
import { useAuth, authHeader } from '../hooks/useAuth';
import {
  AppBar, Toolbar, Typography, Button, Box, Container,
  Grid, Card, CardContent, TextField, MenuItem, Select,
  InputLabel, FormControl, Tabs, Tab, Table, TableBody,
  TableCell, TableContainer, TableHead, TableRow, Paper,
  IconButton, Alert, Chip, Divider,
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import AddIcon from '@mui/icons-material/Add';

// ─── Constantes ───────────────────────────────────────────────────────────────

const API = 'http://localhost:3001/api';

const COLORES = ['#f44336','#2196f3','#ff9800','#4caf50','#9c27b0','#00bcd4','#f492ff','#fff537'];
const MESES   = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
const ANIOS   = [2024,2025,2026,2027,2028,2029,2030,2031,2032];

// ─── Tipos ────────────────────────────────────────────────────────────────────

interface Movimiento {
  id: number;
  monto: number;
  descripcion: string;
  fecha: string;
  categoria_id?: number;
  categoria_nombre?: string;
}
interface Resumen   { totalIngresos: number; totalGastos: number; balance: number; }
interface Categoria { id: number; nombre: string; }

// ─── Helpers ──────────────────────────────────────────────────────────────────

const fmt  = (n: number) => `$${n.toLocaleString('es-DO', { minimumFractionDigits: 2 })}`;
const hoy  = () => new Date().toISOString().split('T')[0];

/** Agrupa los montos de una lista por mes para el año dado */
const porMes = (lista: Movimiento[], anio: number) =>
  lista.reduce((acc, m) => {
    const d = new Date(m.fecha);
    if (d.getFullYear() === anio) acc[d.getMonth()] += parseFloat(m.monto as any) || 0;
    return acc;
  }, Array(12).fill(0) as number[]);

// ─── Sub-componentes ──────────────────────────────────────────────────────────

const TablaIngresos = ({ rows, onDelete, scrollable = false }: {
  rows: Movimiento[]; onDelete: (id: number) => void; scrollable?: boolean;
}) => (
  <TableContainer component={Paper} sx={scrollable ? { maxHeight: 400, mb: 3 } : { mb: 3 }}>
    <Table stickyHeader={scrollable} size="small">
      <TableHead>
        <TableRow>
          {['Fecha','Descripción','Monto',''].map(col => (
            <TableCell key={col} align={col === 'Monto' ? 'right' : col === '' ? 'center' : 'left'}
              sx={{ color: '#2e7d32', bgcolor: '#e8f5e9' }}>{col}</TableCell>
          ))}
        </TableRow>
      </TableHead>
      <TableBody>
        {rows.length === 0
          ? <TableRow><TableCell colSpan={4} align="center">Sin ingresos registrados</TableCell></TableRow>
          : rows.map(i => (
            <TableRow key={i.id}>
              <TableCell>{i.fecha?.split('T')[0]}</TableCell>
              <TableCell>{i.descripcion || '-'}</TableCell>
              <TableCell align="right" sx={{ color: '#2e7d32', fontWeight: 'bold' }}>{fmt(i.monto)}</TableCell>
              <TableCell align="center">
                <IconButton size="small" onClick={() => onDelete(i.id)} color="error"><DeleteIcon fontSize="small" /></IconButton>
              </TableCell>
            </TableRow>
          ))}
      </TableBody>
    </Table>
  </TableContainer>
);

const TablaGastos = ({ rows, onDelete, scrollable = false }: {
  rows: Movimiento[]; onDelete: (id: number) => void; scrollable?: boolean;
}) => (
  <TableContainer component={Paper} sx={scrollable ? { maxHeight: 400 } : {}}>
    <Table stickyHeader={scrollable} size="small">
      <TableHead>
        <TableRow>
          {['Fecha','Descripción','Categoría','Monto',''].map(col => (
            <TableCell key={col} align={col === 'Monto' ? 'right' : col === '' ? 'center' : 'left'}
              sx={{ color: '#c62828', bgcolor: '#ffebee' }}>{col}</TableCell>
          ))}
        </TableRow>
      </TableHead>
      <TableBody>
        {rows.length === 0
          ? <TableRow><TableCell colSpan={5} align="center">Sin gastos registrados</TableCell></TableRow>
          : rows.map(g => (
            <TableRow key={g.id}>
              <TableCell>{g.fecha?.split('T')[0]}</TableCell>
              <TableCell>{g.descripcion || '-'}</TableCell>
              <TableCell><Chip label={g.categoria_nombre || '-'} size="small" /></TableCell>
              <TableCell align="right" sx={{ color: '#c62828', fontWeight: 'bold' }}>{fmt(g.monto)}</TableCell>
              <TableCell align="center">
                <IconButton size="small" onClick={() => onDelete(g.id)} color="error"><DeleteIcon fontSize="small" /></IconButton>
              </TableCell>
            </TableRow>
          ))}
      </TableBody>
    </Table>
  </TableContainer>
);

// Gráfica de torta con conic-gradient
const GraficaTorta = ({ etiquetas, valores, total }: {
  etiquetas: string[]; valores: number[]; total: number;
}) => {
  const gradient = etiquetas.map((_, i) => {
    const inicio = valores.slice(0, i).reduce((a, b) => a + b, 0);
    return `${COLORES[i % COLORES.length]} ${(inicio / total) * 100}% ${((inicio + valores[i]) / total) * 100}%`;
  }).join(',');

  return (
    <>
      <Box sx={{ width: 300, height: 300, borderRadius: '50%', background: total > 0 ? `conic-gradient(${gradient})` : '#e0e0e0' }} />
      <Box sx={{ mt: 3, display: 'flex', flexWrap: 'wrap', gap: 2 }}>
        {etiquetas.map((cat, i) => (
          <Box key={cat} sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
            <Box sx={{ width: 16, height: 16, bgcolor: COLORES[i % COLORES.length] }} />
            <Typography variant="body2">{cat}: {valores[i].toLocaleString('es-DO', { style: 'currency', currency: 'DOP' })}</Typography>
          </Box>
        ))}
      </Box>
    </>
  );
};

// Gráfica de barras verticales por mes (el max se calcula internamente)
const GraficaBarras = ({ titulo, datos, color }: { titulo: string; datos: number[]; color: string }) => {
  const max = Math.max(...datos, 1);
  return (
    <Box sx={{ width: '100%' }}>
      <Typography variant="h6" gutterBottom>{titulo}</Typography>
      <Box sx={{ display: 'flex', alignItems: 'flex-end', gap: 1, height: 200 }}>
        {datos.map((v, i) => (
          <Box key={i} sx={{ flex: 1, textAlign: 'center' }}>
            <Box sx={{ height: v > 0 ? `${(v / max) * 180}px` : '2px', bgcolor: color, borderRadius: 1 }} />
            <Typography variant="caption">{MESES[i]}</Typography>
          </Box>
        ))}
      </Box>
      <Box sx={{ mt: 3, display: 'flex', flexWrap: 'wrap', gap: 2 }}>
        {datos.map((v, i) => (
          <Box key={i} sx={{ display: 'flex', gap: 0.5 }}>
            <Typography variant="body2" fontWeight="bold">{MESES[i]}:</Typography>
            <Typography variant="body2">{v.toLocaleString('es-DO', { style: 'currency', currency: 'DOP' })}</Typography>
          </Box>
        ))}
      </Box>
    </Box>
  );
};

// ─── Componente Principal ─────────────────────────────────────────────────────

const Dashboard: React.FC = () => {
  const { username, logout } = useAuth();
  const [tab, setTab] = useState(0);

  // Datos del servidor
  const [ingresos,   setIngresos]   = useState<Movimiento[]>([]);
  const [gastos,     setGastos]     = useState<Movimiento[]>([]);
  const [categorias, setCategorias] = useState<Categoria[]>([]);
  const [resumen,    setResumen]    = useState<Resumen>({ totalIngresos: 0, totalGastos: 0, balance: 0 });
  const [success,    setSuccess]    = useState('');

  // Formulario ingreso
  const [montoI, setMontoI] = useState('');
  const [descI,  setDescI]  = useState('');
  const [fechaI, setFechaI] = useState(hoy());

  // Formulario gasto
  const [montoG, setMontoG] = useState('');
  const [descG,  setDescG]  = useState('');
  const [fechaG, setFechaG] = useState(hoy());
  const [catG,   setCatG]   = useState('');

  // Filtros
  const [filtroDesde,     setFiltroDesde]     = useState('');
  const [filtroHasta,     setFiltroHasta]     = useState('');
  const [filtroCategoria, setFiltroCategoria] = useState('');

  // Efectos visuales en las tarjetas de resumen
  const [ingresoBrilla, setIngresoBrilla] = useState(false);
  const [gastoBrilla,   setGastoBrilla]   = useState(false);

  // Año para las gráficas de barras
  const [anio, setAnio] = useState(new Date().getFullYear());

  // Datos derivados para la torta
  const gastosPorCat = gastos.reduce((acc: Record<string, number>, g) => {
    const cat = g.categoria_nombre || 'Sin categoría';
    acc[cat] = (acc[cat] || 0) + Number(g.monto);
    return acc;
  }, {});
  const etiquetas  = Object.keys(gastosPorCat);
  const valores    = Object.values(gastosPorCat);
  const totalTorta = valores.reduce((a, b) => a + b, 0);

  // Datos derivados para las barras
  const gastosMes   = useMemo(() => porMes(gastos,   anio), [gastos,   anio]);
  const ingresosMes = useMemo(() => porMes(ingresos, anio), [ingresos, anio]);

  // ── Fetch ─────────────────────────────────────────────────────────────────

  const fetchData = useCallback(async () => {
    const [i, g, r, c] = await Promise.all([
      axios.get(`${API}/ingresos`,   authHeader()),
      axios.get(`${API}/gastos`,     authHeader()),
      axios.get(`${API}/resumen`,    authHeader()),
      axios.get(`${API}/categorias`, authHeader()),
    ]);
    setIngresos(i.data); setGastos(g.data); setResumen(r.data); setCategorias(c.data);
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  // ── Acciones ──────────────────────────────────────────────────────────────

  const flash = (setter: (v: boolean) => void) => { setter(true); setTimeout(() => setter(false), 400); };
  const ok    = (msg: string) => { setSuccess(msg); setTimeout(() => setSuccess(''), 3000); };

  const addIngreso = async (e: React.FormEvent) => {
    e.preventDefault();
    await axios.post(`${API}/ingresos`, { monto: montoI, descripcion: descI, fecha: fechaI }, authHeader());
    setMontoI(''); setDescI(''); setFechaI(hoy());
    ok('Ingreso agregado'); flash(setIngresoBrilla); fetchData();
  };

  const addGasto = async (e: React.FormEvent) => {
    e.preventDefault();
    if (parseFloat(montoG) > resumen.balance) { alert('No puedes gastar más de tu balance disponible'); return; }
    await axios.post(`${API}/gastos`, { monto: montoG, descripcion: descG, fecha: fechaG, categoria_id: catG }, authHeader());
    setMontoG(''); setDescG(''); setFechaG(hoy()); setCatG('');
    ok('Gasto agregado'); flash(setGastoBrilla); fetchData();
  };

  const deleteIngreso = async (id: number) => { await axios.delete(`${API}/ingresos/${id}`, authHeader()); fetchData(); };
  const deleteGasto   = async (id: number) => { await axios.delete(`${API}/gastos/${id}`,   authHeader()); fetchData(); };

  const filtrar = async () => {
    const gp: any = {};
    if (filtroDesde)     gp.desde        = filtroDesde;
    if (filtroHasta)     gp.hasta        = filtroHasta;
    if (filtroCategoria) gp.categoria_id = filtroCategoria;

    const [g, i] = await Promise.all([
      axios.get(`${API}/gastos`,   { headers: authHeader().headers, params: gp }),
      axios.get(`${API}/ingresos`, { headers: authHeader().headers, params: {
        ...(filtroDesde && { desde: filtroDesde }),
        ...(filtroHasta && { hasta: filtroHasta }),
      }}),
    ]);
    setGastos(g.data); setIngresos(i.data);
  };

  // ── Render ────────────────────────────────────────────────────────────────

  return (
    <Box sx={{ minHeight: '100vh', bgcolor: '#f0f4f8' }}>

      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>💰 Gastos Personales</Typography>
          <Typography variant="body2" sx={{ mr: 2 }}>Hola, {username}</Typography>
          <Button color="inherit" onClick={logout}>Cerrar Sesión</Button>
        </Toolbar>
      </AppBar>

      <Container maxWidth="lg" sx={{ mt: 4, pb: 4 }}>
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        {/* Tarjetas de resumen */}
        <Grid container spacing={3} sx={{ mb: 4 }}>
          {[
            { label: 'Total Ingresos',     value: resumen.totalIngresos, color: '#2e7d32' },
            { label: 'Total Gastos',       value: resumen.totalGastos,   color: '#c62828' },
            { label: 'Balance Disponible', value: resumen.balance,       color: resumen.balance >= 0 ? '#1565c0' : '#c62828' },
          ].map(item => (
            <Grid item xs={12} md={4} key={item.label}>
              <Card elevation={3} sx={{
                backgroundColor:
                  item.label === 'Total Ingresos' && ingresoBrilla ? '#e6f9ec' :
                  item.label === 'Total Gastos'   && gastoBrilla   ? '#fde0e2' : '#fff',
                transition: ingresoBrilla || gastoBrilla ? 'none' : 'background-color 0.8s ease',
              }}>
                <CardContent sx={{ textAlign: 'center' }}>
                  <Typography variant="body2" color="text.secondary">{item.label}</Typography>
                  <Typography variant="h4" fontWeight="bold" sx={{ color: item.color }}>{fmt(item.value)}</Typography>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>

        <Paper elevation={2}>
          <Tabs value={tab} onChange={(_, v) => setTab(v)} sx={{ borderBottom: 1, borderColor: 'divider' }}>
            <Tab label="Agregar Ingreso" />
            <Tab label="Agregar Gasto" />
            <Tab label="Movimientos" />
            <Tab label="Gráficas" />
          </Tabs>

          {/* Tab 0 — Ingreso */}
          {tab === 0 && (
            <Box sx={{ p: 3 }}>
              <Typography variant="h6" gutterBottom>Nuevo Ingreso</Typography>
              <Box component="form" onSubmit={addIngreso}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={4}>
                    <TextField fullWidth label="Monto" type="number" required value={montoI} onChange={e => setMontoI(e.target.value)} inputProps={{ min: 0, step: '0.01' }} />
                  </Grid>
                  <Grid item xs={12} sm={4}>
                    <TextField fullWidth label="Descripción" value={descI} onChange={e => setDescI(e.target.value)} />
                  </Grid>
                  <Grid item xs={12} sm={4}>
                    <TextField fullWidth label="Fecha" type="date" required value={fechaI} onChange={e => setFechaI(e.target.value)} InputLabelProps={{ shrink: true }} />
                  </Grid>
                </Grid>
                <Button type="submit" variant="contained" color="success" startIcon={<AddIcon />} sx={{ mt: 2 }}>Agregar Ingreso</Button>
              </Box>
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mt: 3, mb: 1, color: '#2e7d32' }}>Ingresos</Typography>
              <TablaIngresos rows={ingresos.slice(0, 5)} onDelete={deleteIngreso} />
            </Box>
          )}

          {/* Tab 1 — Gasto */}
          {tab === 1 && (
            <Box sx={{ p: 3 }}>
              <Typography variant="h6" gutterBottom>Nuevo Gasto</Typography>
              <Box component="form" onSubmit={addGasto}>
                <Grid container spacing={2}>
                  <Grid item xs={12} sm={3}>
                    <TextField fullWidth label="Monto" type="number" required value={montoG} onChange={e => setMontoG(e.target.value)} inputProps={{ min: 0, step: '0.01' }} />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <TextField fullWidth label="Descripción" value={descG} onChange={e => setDescG(e.target.value)} />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <TextField fullWidth label="Fecha" type="date" required value={fechaG} onChange={e => setFechaG(e.target.value)} InputLabelProps={{ shrink: true }} />
                  </Grid>
                  <Grid item xs={12} sm={3}>
                    <FormControl fullWidth required>
                      <InputLabel>Categoría</InputLabel>
                      <Select value={catG} label="Categoría" onChange={e => setCatG(e.target.value)}>
                        {categorias.map(c => <MenuItem key={c.id} value={c.id}>{c.nombre}</MenuItem>)}
                      </Select>
                    </FormControl>
                  </Grid>
                </Grid>
                <Button type="submit" variant="contained" color="error" startIcon={<AddIcon />} sx={{ mt: 2 }}>Agregar Gasto</Button>
              </Box>
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mt: 3, mb: 1, color: '#c62828' }}>Gastos</Typography>
              <TablaGastos rows={gastos.slice(0, 5)} onDelete={deleteGasto} />
            </Box>
          )}

          {/* Tab 2 — Movimientos con filtros */}
          {tab === 2 && (
            <Box sx={{ p: 3 }}>
              <Typography variant="h6" gutterBottom>Filtrar Movimientos</Typography>
              <Grid container spacing={2} sx={{ mb: 3 }}>
                <Grid item xs={12} sm={3}>
                  <TextField fullWidth label="Desde" type="date" value={filtroDesde} onChange={e => setFiltroDesde(e.target.value)} InputLabelProps={{ shrink: true }} />
                </Grid>
                <Grid item xs={12} sm={3}>
                  <TextField fullWidth label="Hasta" type="date" value={filtroHasta} onChange={e => setFiltroHasta(e.target.value)} InputLabelProps={{ shrink: true }} />
                </Grid>
                <Grid item xs={12} sm={3}>
                  <FormControl fullWidth>
                    <InputLabel>Categoría</InputLabel>
                    <Select value={filtroCategoria} label="Categoría" onChange={e => setFiltroCategoria(e.target.value as string)}>
                      <MenuItem value="">Todas</MenuItem>
                      {categorias.map(c => <MenuItem key={c.id} value={c.id}>{c.nombre}</MenuItem>)}
                    </Select>
                  </FormControl>
                </Grid>
                <Grid item xs={12} sm={3} sx={{ display: 'flex', alignItems: 'center' }}>
                  <Button variant="outlined" onClick={filtrar} fullWidth>Filtrar</Button>
                </Grid>
              </Grid>
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mb: 1, color: '#2e7d32' }}>Ingresos</Typography>
              <TablaIngresos rows={ingresos} onDelete={deleteIngreso} scrollable />
              <Typography variant="subtitle1" fontWeight="bold" sx={{ mt: 3, mb: 1, color: '#c62828' }}>Gastos</Typography>
              <TablaGastos rows={gastos} onDelete={deleteGasto} scrollable />
            </Box>
          )}

          {/* Tab 3 — Gráficas */}
          {tab === 3 && (
            <Box sx={{ p: 3, display: 'flex', flexDirection: 'column', alignItems: 'center', mt: 2 }}>
              <Typography variant="h6" gutterBottom>Gastos por Categoría</Typography>
              <GraficaTorta etiquetas={etiquetas} valores={valores} total={totalTorta} />

              <Divider sx={{ my: 10, width: '100%' }}>
                <Typography variant="caption">Gráfica de barra</Typography>
              </Divider>

              <FormControl sx={{ mt: 2, mb: 3, minWidth: 120 }}>
                <InputLabel>Año</InputLabel>
                <Select value={anio} label="Año" onChange={e => setAnio(Number(e.target.value))}>
                  {ANIOS.map(a => <MenuItem key={a} value={a}>{a}</MenuItem>)}
                </Select>
              </FormControl>

              <GraficaBarras titulo={`Gastos de (${anio})`}   datos={gastosMes}   color="#c81505" />
              <Box sx={{ mt: 6, width: '100%' }}>
                <GraficaBarras titulo={`Ingresos de (${anio})`} datos={ingresosMes} color="#2e7d32" />
              </Box>
            </Box>
          )}
        </Paper>
      </Container>
    </Box>
  );
};

export default Dashboard;
